import React, { useEffect, useState, useCallback } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const TimbangMuat = () => {
  const navigate = useNavigate();

  const [truck, setTruck] = useState(null);
  const [loading, setLoading] = useState(false);
  const [list, setList] = useState([]);

  const [form, setForm] = useState({
    itemType: "",
    no_palka: "",
    bruto_belawan: "",
    tara_belawan: "",
  });

  // ================= RFID =================
  const fetchRFID = useCallback(async () => {
    try {
      setLoading(true);

      const res = await axios.get("http://localhost:5000/api/rfid/latest");

      const truckData = res.data?.truck;

      if (truckData?.truckId) {
        setTruck(truckData);
        fetchData(truckData.truckId);
      } else {
        setTruck(null);
      }
    } catch (err) {
      console.error("RFID ERROR:", err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (!truck) fetchRFID();
    }, 2000);

    return () => clearInterval(interval);
  }, [truck, fetchRFID]);

  // ================= HANDLE =================
  const handleChange = (e) => {
    setForm((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  // ================= SUBMIT =================
  const handleSubmit = async (e) => {
    e.preventDefault();

    const truckId = truck?.truckId;

    if (!truckId) {
      alert("RFID belum terbaca!");
      return;
    }

    if (!form.itemType || !form.no_palka) {
      alert("Item dan No Palka wajib diisi");
      return;
    }

    const bruto = Number(form.bruto_belawan || 0);
    const tara = Number(form.tara_belawan || 0);

    const payload = {
      truckId,
      itemType: form.itemType,
      no_palka: form.no_palka,
      bruto_belawan: bruto,
      tara_belawan: tara,
      netto_belawan: bruto - tara,
      unit: "kg",
      status_timbang: "BRUTO",
    };

    console.log("PAYLOAD:", payload);

    try {
      await axios.post("http://localhost:5000/api/loadings", payload, {
        headers: { "Content-Type": "application/json" },
      });

      alert("Data berhasil disimpan");

      setForm({
        itemType: "",
        no_palka: "",
        bruto_belawan: "",
        tara_belawan: "",
      });

      fetchData(truckId);
    } catch (err) {
      console.error("BACKEND ERROR:", err.response?.data || err.message);
      alert(err.response?.data?.message || "Gagal simpan data");
    }
  };

  // ================= FETCH DATA =================
  const fetchData = async (truckId) => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/loadings/${truckId}`
      );
      setList(res.data || []);
    } catch (err) {
      console.error("FETCH ERROR:", err);
    }
  };

  // ================= UI =================
  return (
    <div className="p-8 min-h-screen bg-gradient-to-br from-blue-100 to-white">

      <h1 className="text-3xl font-bold text-center mb-8">
        ⚖️ Timbang Muat Belawan System
      </h1>

      {loading && (
        <div className="flex justify-center">
          <div className="animate-spin w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full"></div>
        </div>
      )}

      {!truck && !loading && (
        <p className="text-center text-gray-600">Menunggu RFID...</p>
      )}

      {truck && (
        <div className="max-w-6xl mx-auto bg-white p-6 shadow rounded">

          {/* INFO TRUCK */}
          <div className="mb-6 grid grid-cols-2 gap-4">
            <div><b>Truck:</b> {truck.truckId}</div>
            <div><b>Driver:</b> {truck.driver}</div>
            <div><b>Tipe:</b> {truck.truckType}</div>
          </div>

          {/* FORM */}
          <form onSubmit={handleSubmit} className="grid grid-cols-2 gap-4">

            <input
              name="itemType"
              placeholder="Item"
              value={form.itemType}
              onChange={handleChange}
              className="border p-2"
              required
            />

            <input
              name="no_palka"
              placeholder="No Palka"
              value={form.no_palka}
              onChange={handleChange}
              className="border p-2"
              required
            />

            <input
              name="bruto_belawan"
              type="number"
              placeholder="Bruto"
              value={form.bruto_belawan}
              onChange={handleChange}
              className="border p-2"
              required
            />

            <input
              name="tara_belawan"
              type="number"
              placeholder="Tara"
              value={form.tara_belawan}
              onChange={handleChange}
              className="border p-2"
              required
            />

            {/* AUTO NETTO */}
            <div className="border p-2 bg-gray-100">
              Netto: {Number(form.bruto_belawan || 0) - Number(form.tara_belawan || 0)}
            </div>

            <button
              type="submit"
              className="col-span-2 bg-blue-600 text-white p-2"
            >
              Simpan
            </button>

          </form>

          {/* TABLE */}
          <div className="mt-10">
            <table className="w-full border text-sm">
              <thead className="bg-blue-200">
                <tr>
                  <th>Item</th>
                  <th>No Palka</th>
                  <th>Bruto</th>
                  <th>Tara</th>
                  <th>Netto</th>
                </tr>
              </thead>

              <tbody>
                {list.map((item, i) => (
                  <tr key={i}>
                    <td>{item.itemType}</td>
                    <td>{item.no_palka}</td>
                    <td>{item.bruto_belawan}</td>
                    <td>{item.tara_belawan}</td>
                    <td>{item.netto_belawan}</td>
                  </tr>
                ))}

                {list.length === 0 && (
                  <tr>
                    <td colSpan="5" className="text-center p-4">
                      Belum ada data
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>

        </div>
      )}
    </div>
  );
};

export default TimbangMuat;
